+            .enclave_identity
+            .attributes_mask
+            .trim_start_matches("0x"),
+    )
+    .map_err(|_| Error::QeIdentityConstraintViolation("attributesMask"))?;
+    if expected_attr.len() != 16 || attr_mask.len() != 16 {
+        return Err(Error::QeIdentityConstraintViolation("attributes"));
+    }
